mapper.select:
/* TM_ECS_SCRIN_BTN_MNG_Dao_retrieveBtnInfo */ SELECT intn_sys_div_cd, btn_seq, btn_nm, btn_athr_vu FROM tm_ecs_scrin_btn_mng
AND intn_sys_div_cd = #{intnSysDivCd}
AND btn_nm LIKE '%' || #{btnNm} || '%'
ORDER BY btn_seq

mapper.update:
/* TM_ECS_SCRIN_BTN_MNG_Dao_updateScrinBtn */
UPDATE
	tm_ecs_scrin_btn_mng
SET
	btn_nm = #{btnNm},
	btn_athr_vu = #{btnAthrVu},
	last_updt_dt = SYSDATE,
	last_updusr_id = #{lastUpdusrId}
WHERE
	intn_sys_div_cd = #{intnSysDivCd}
	AND btn_seq = #{btnSeq}

mapper.delete:
/* TM_ECS_SCRIN_BTN_MNG_Dao_deleteScrinBtn */
DELETE FROM
	tm_ecs_scrin_btn_mng 
WHERE
	intn_sys_div_cd = #{intnSysDivCd}
	AND btn_seq = #{btnSeq}
